using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person>, not JsonTypeInfo
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata  : {personInfo.Type.Name}  (JsonTypeInfo<{personInfo.Type.Name}>)");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Round-trip serialize : {json}");

Person? p = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Round-trip deserialize: {p}");

// 2) Probe without throwing — TryGetTypeInfo returns false instead of an exception
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed);
Console.WriteLine($"\nTryGetTypeInfo(Person) => found={found}, type={probed?.Type.Name}");

// Now try a type whose metadata is NOT available (custom resolver that resolves nothing)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new NullResolver()
};

bool missing = limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probedMissing);
Console.WriteLine($"TryGetTypeInfo(Person) on empty resolver => found={missing}, info={probedMissing?.ToString() ?? "null"}");

// -- helper types --------------------------------------------------------

record Person(string Name, int Age);

// A resolver that resolves nothing — simulates "metadata not available"
sealed class NullResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

